<template><div class="panel"><div class="section-head"><div><h2>{{ t('logs.operationTitle') }}</h2><p>{{ t('logs.operationDescription') }}</p></div><el-button @click="load">{{ t('common.refresh') }}</el-button></div><el-table :data="rows"><el-table-column prop="operatedAt" :label="t('common.time')" width="180"/><el-table-column prop="username" :label="t('common.user')"/><el-table-column prop="method" :label="t('logs.method')" width="80"/><el-table-column prop="path" :label="t('logs.interface')"/><el-table-column prop="durationMs" :label="t('logs.duration')"/><el-table-column :label="t('common.result')"><template #default="s"><el-tag :type="s.row.success?'success':'danger'">{{s.row.success?t('logs.success'):t('logs.failed')}}</el-tag></template></el-table-column><el-table-column prop="errorMessage" :label="t('logs.error')" show-overflow-tooltip/></el-table><el-pagination v-model:current-page="query.page" :page-size="query.size" :total="total" layout="total, prev, pager, next" @current-change="load"/></div></template><script setup>import{onMounted,reactive,ref}from'vue';import{useI18n}from'vue-i18n';import http from'../api/http';const{t}=useI18n();const rows=ref([]),total=ref(0);const query=reactive({page:1,size:5});/** 加载操作日志。 */async function load(){const response=await http.get('/system/operation-logs',{params:query});rows.value=response.data.items;total.value=response.data.total}onMounted(load)</script>
<!-- 操作日志页面：展示系统写操作的脱敏审计记录。 -->
